import sys, json

data = json.load(sys.stdin)

for conv in data:
    title = conv.get('title', '')
    mapping = conv.get('mapping', {})

    all_text = title + ' '
    for node_id, node in mapping.items():
        msg = node.get('message')
        if msg and msg.get('content') and msg['content'].get('parts'):
            for part in msg['content']['parts']:
                if isinstance(part, str):
                    all_text += part + ' '

    if 'IQE' in all_text or 'iqe' in all_text.lower():
        print(f'Found IQE in conversation: {title}')

    terms_found = []
    for term in ['compound semiconductor', 'epitaxy', 'epiwafer', 'VCSEL', 'Win Semi', 'GaN power', 'microLED']:
        if term.lower() in all_text.lower():
            terms_found.append(term)
    if terms_found:
        print(f'Found {terms_found} in: {title}')
